import {
  createCheckoutSession as createExtensionCheckoutSession,
  getStripePayments,
} from "@stripe/firestore-stripe-payments";
import { httpsCallable } from "firebase/functions";

import { app, auth, functions } from "@/lib/firebase/client";

type ExtensionCheckoutResult = {
  sessionId?: string;
  url?: string;
};

const payments = getStripePayments(app, {
  customersCollection: "customers",
  productsCollection: "products",
});

export async function createCheckoutSession(priceId?: string): Promise<ExtensionCheckoutResult> {
  const user = auth.currentUser;

  if (!user) {
    throw new Error("You must be signed in.");
  }

  if (!priceId) {
    throw new Error("Missing Stripe price ID.");
  }

  const baseUrl = process.env.NEXT_PUBLIC_APP_URL ?? window.location.origin;
  const session = await createExtensionCheckoutSession(
    payments,
    {
      price: priceId,
      mode: "subscription",
      success_url: `${baseUrl}/checkout/return?session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${baseUrl}/pricing`,
      allow_promotion_codes: true,
    },
    { timeoutMillis: 20000 },
  );

  return {
    sessionId: session.id,
    url: session.url,
  };
}

export async function createBillingPortalSession() {
  const user = auth.currentUser;

  if (!user) {
    throw new Error("You must be signed in.");
  }

  const baseUrl = process.env.NEXT_PUBLIC_APP_URL ?? window.location.origin;
  const createPortalLink = httpsCallable<{ returnUrl: string }, { url: string }>(
    functions,
    "ext-firestore-stripe-payments-createPortalLink",
  );

  const response = await createPortalLink({ returnUrl: `${baseUrl}/dashboard/billing` });
  if (!response.data?.url) {
    throw new Error("Missing billing portal URL from Firebase Stripe extension.");
  }

  return { url: response.data.url };
}
